INSERT INTO exercises (slug, name, subcategory, difficulty, equipment, sets_recommended, reps_recommended, image_url, instructions, description, is_active, is_public, updated_at) VALUES
('agachamento', 'Agachamento', 'Joelho / Quadril', 'iniciante', ARRAY['Banco/Cadeira']::text[], 3, 12, '/exercises/illustrations/agachamento-livre.avif', 'Mantenha os pés afastados na largura dos ombros, desça como se fosse sentar em uma cadeira invisível, mantendo o peito aberto e o peso nos calcanhares.', 'Exercício multiarticular para quadríceps, glúteos e core.', true, true, NOW()),
('agachamento-bulgaro', 'Agachamento Búlgaro', 'Joelho / Quadril', 'intermediario', ARRAY['Banco', 'Halter']::text[], 3, 12, '/exercises/illustrations/agachamento-bulgaro.avif', 'Coloque um pé atrás em um banco e o outro à frente. Desça o quadril verticalmente mantendo o tronco levemente inclinado, focando o esforço na perna da frente.', 'Exercício unipodal avançado para força de quadríceps e glúteos com componente de estabilidade.', true, true, NOW()),
('agachamento-sumô', 'Agachamento Sumô', 'Joelho / Quadril', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/agachamento-sumo.avif', 'Afaste os pés além da largura dos ombros com as pontas viradas para fora. Desça o quadril mantendo os joelhos alinhados com os pés e o tronco ereto.', 'Variação de agachamento com base ampla para maior ativação de adutores.', true, true, NOW()),
('agachamento-goblet', 'Agachamento Goblet', 'Joelho / Quadril', 'intermediario', ARRAY['Kettlebell', 'Halter']::text[], 3, 12, '/exercises/illustrations/agachamento-goblet.avif', 'Segure um peso junto ao peito, mantenha os cotovelos para baixo e realize o agachamento garantindo que o tronco permaneça vertical.', 'Agachamento com carga frontal que auxilia na manutenção da postura ereta.', true, true, NOW()),
('agachamento-pistol', 'Agachamento Pistol', 'Joelho / Quadril', 'avancado', ARRAY[]::text[], 4, 8, '/exercises/illustrations/agachamento-pistol.png', 'Equilibre-se em uma perna, estenda a outra à frente e desça o máximo possível com controle, mantendo o calcanhar de apoio no chão.', 'Exercício de altíssimo nível para força unipodal, equilíbrio e mobilidade de tornozelo.', true, true, NOW()),
('agachamento-parede', 'Agachamento na Parede', 'Joelho', 'iniciante', ARRAY['Parede']::text[], 3, 45, '/exercises/illustrations/agachamento-parede.avif', 'Encoste as costas na parede e desça até que seus joelhos formem um ângulo de 90 graus. Mantenha a posição, sentindo o esforço nas coxas, sem deixar os joelhos ultrapassarem a ponta dos pés.', 'Isométrico para fortalecimento de quadríceps.', true, true, NOW()),
('afundo', 'Afundo', 'Joelho / Quadril', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/afundo.avif', 'Dê um passo à frente e desça o quadril até que ambos os joelhos estejam em cerca de 90 graus. Mantenha o tronco ereto e o joelho da frente alinhado com o pé.', 'Exercício funcional para membros inferiores com foco em quadríceps e estabilidade.', true, true, NOW()),
('afundo-lateral', 'Afundo Lateral', 'Joelho / Quadril', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/afundo-lateral.avif', 'Dê um passo largo para o lado, dobrando o joelho da perna que moveu enquanto mantém a outra esticada. Mantenha os pés apontados para frente.', 'Foco em adutores e estabilidade no plano frontal.', true, true, NOW()),
('afundo-reverso', 'Afundo Reverso', 'Joelho / Quadril', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/afundo-reverso.avif', 'Dê um passo para trás e desça o joelho de trás em direção ao chão, mantendo o peso na perna da frente e o tronco ereto.', 'Variação que costuma ser mais confortável para o joelho do que o afundo frontal.', true, true, NOW()),
('afundo-caminando', 'Afundo Caminhando', 'Joelho / Quadril', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/afundo-caminhando.avif', 'Realize afundos sucessivos alternando as pernas enquanto se desloca para frente, mantendo o controle do equilíbrio em cada passo.', 'Variação dinâmica do afundo para progressão funcional.', true, true, NOW()),
('leg-press', 'Leg Press', 'Joelho / Quadril', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/leg-press.avif', 'Posicione os pés na plataforma, empurre-a estendendo as pernas sem travar os joelhos e retorne de forma lenta e controlada.', 'Fortalecimento global de MMII em cadeia fechada com carga controlada.', true, true, NOW()),
('cadeira-extensora', 'Cadeira Extensora', 'Joelho', 'iniciante', ARRAY['Banco/Cadeira']::text[], 3, 12, '/exercises/illustrations/extensao-joelho-cadeira.avif', 'Sente-se no aparelho e estenda os joelhos completamente contra a resistência, controlando a descida lenta.', 'Isolamento de quadríceps em cadeia cinética aberta.', true, true, NOW()),
('cadeira-flexora', 'Cadeira Flexora', 'Joelho', 'iniciante', ARRAY['Foam Roller', 'Banco/Cadeira']::text[], 3, 12, '/exercises/illustrations/flexao-joelho-cadeira.avif', 'Sente-se ou deite-se no aparelho e flexione os joelhos puxando o rolo em direção às coxas, controlando o retorno lento.', 'Isolamento de isquiotibiais.', true, true, NOW()),
('stiff', 'Stiff', 'Posterior / Quadril', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/deadlift_dumbbells.avif', 'Com os joelhos levemente flexionados, desça o tronco mantendo as costas retas e empurrando o quadril para trás até sentir o alongamento atrás das coxas.', 'Fortalecimento de cadeia posterior com foco em isquiotibiais e glúteos.', true, true, NOW()),
('step-up', 'Step-Up', 'Joelho / Quadril', 'intermediario', ARRAY['Banco/Cadeira', 'Step/Degrau']::text[], 3, 12, '/exercises/illustrations/step-up-frontal.avif', 'Coloque um pé sobre o banco ou degrau e suba, estendendo o joelho completamente. Desça de forma controlada, mantendo o alinhamento do joelho de apoio.', 'Exercício funcional de subida com foco em controle motor e força unipodal.', true, true, NOW()),
('step-down', 'Step-Down', 'Joelho', 'intermediario', ARRAY['Step/Degrau']::text[], 3, 12, '/exercises/illustrations/descida-controlada-de-degrau.avif', 'Em cima de um degrau, desça lentamente uma perna até tocar o calcanhar no chão, mantendo o joelho de apoio alinhado e sem deixar ''cair''.', 'Exercício excêntrico para controle de valgo dinâmico.', true, true, NOW()),
('nordico', 'Nordic Hamstring', 'Posterior da Coxa', 'avancado', ARRAY[]::text[], 4, 8, '/exercises/illustrations/nordic-hamstring-beginner.avif', 'Ajoelhado com os calcanhares presos, desça o tronco o mais devagar possível, resistindo à queda com a parte de trás das coxas.', 'Prevenção de lesões em isquiotibiais.', true, true, NOW()),
('ponte-gluteo', 'Ponte de Glúteo', 'Quadril / Glúteo', 'iniciante', ARRAY[]::text[], 3, 15, '/exercises/illustrations/ponte-gluteo.avif', 'Deitado de costas com os joelhos dobrados, suba o quadril em direção ao teto apertando bem os glúteos. Mantenha os ombros relaxados no chão.', 'Ativação de glúteo máximo e estabilidade lombo-pélvica.', true, true, NOW()),
('hip-thrust', 'Hip Thrust', 'Quadril / Glúteo', 'intermediario', ARRAY['Banco/Cadeira']::text[], 3, 12, '/exercises/illustrations/elevacao-pelvica.avif', 'Apoie as escápulas em um banco, mantenha os pés no chão e empurre o quadril para cima até alinhar com o tronco, contraindo os glúteos no topo.', 'O padrão-ouro para isolamento e fortalecimento de glúteo máximo.', true, true, NOW()),
('single-leg-bridge', 'Ponte Unilateral', 'Quadril / Glúteo', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/ponte-unipodal.avif', 'Deitado de costas, levante uma perna e empurre o quadril para cima usando apenas o calcanhar da perna que está no chão.', 'Fortalecimento de cadeia posterior com foco em estabilidade pélvica unipodal.', true, true, NOW()),
('leg-raise-lateral', 'Abdução de Quadril Deitado', 'Quadril', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/abducao-quadril-deitado.avif', 'Deitado de lado com as pernas esticadas, levante a perna de cima lateralmente sem girar o quadril para trás.', 'Fortalecimento do glúteo médio em cadeia cinética aberta.', true, true, NOW()),
('clamshell', 'Clamshell', 'Quadril', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/clamshell.avif', 'Deitado de lado com joelhos dobrados, mantenha os calcanhares juntos e abra o joelho de cima como uma concha.', 'Fortalecimento de rotadores externos do quadril.', true, true, NOW()),
('monster-walk', 'Monster Walk', 'Quadril', 'intermediario', ARRAY['Faixa Elástica']::text[], 3, 12, '/exercises/illustrations/caminhada-de-lado-com-miniband-lateral-band-walk.avif', 'Com uma faixa elástica nos tornozelos ou acima dos joelhos, dê passos para o lado mantendo uma posição de semi-agachamento e os joelhos afastados.', 'Exercício dinâmico para ativação de abdutores de quadril em cadeia fechada.', true, true, NOW()),
('kickback', 'Extensão de Quadril', 'Quadril / Glúteo', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/extensao-quadril-quatro-apoios.avif', 'Em quatro apoios, empurre o calcanhar em direção ao teto mantendo o joelho dobrado ou esticado, sem arquear a coluna lombar.', 'Fortalecimento isolado do glúteo máximo.', true, true, NOW()),
('pant-em-pe', 'Panturrilha em Pé', 'Tornozelo / Perna', 'iniciante', ARRAY['Step/Degrau']::text[], 3, 12, '/exercises/illustrations/elevacao-de-panturrilha-em-pe.avif', 'Fique na ponta dos pés, subindo o máximo que puder, e desça lentamente. Pode ser feito no chão ou na borda de um degrau para maior amplitude.', 'Fortalecimento do complexo gastrocnêmio-sóleo.', true, true, NOW()),
('pant-sentado', 'Panturrilha Sentado', 'Tornozelo / Perna', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/elevacao-de-panturrilha-sentado.avif', 'Sentado com os joelhos dobrados e carga sobre as coxas, fique na ponta dos pés e desça de forma controlada.', 'Foco no fortalecimento isolado do músculo sóleo.', true, true, NOW()),
('tibial-ant', 'Dorsiflexão Resistida', 'Tornozelo / Perna', 'iniciante', ARRAY['Parede']::text[], 3, 12, '/exercises/illustrations/tibial-anterior-fortalecimento.avif', 'Encostado em uma parede com os calcanhares à frente, levante as pontas dos pés em direção às canelas e retorne devagar.', 'Fortalecimento do tibial anterior para estabilidade de tornozelo e prevenção de canelite.', true, true, NOW()),
('inversao-tornozelo', 'Inversão Resistida', 'Tornozelo', 'iniciante', ARRAY['Faixa Elástica']::text[], 3, 12, '/exercises/illustrations/inversao-tornozelo-elastico.avif', 'Com uma faixa elástica presa no pé, puxe a planta do pé para dentro contra a resistência e retorne devagar.', 'Fortalecimento do tibial posterior em inversão.', true, true, NOW()),
('eversao-tornozelo', 'Eversão Resistida', 'Tornozelo', 'iniciante', ARRAY['Faixa Elástica']::text[], 3, 12, '/exercises/illustrations/eversao-tornozelo-elastico.avif', 'Com uma faixa elástica presa no pé, puxe a borda lateral do pé para fora contra a resistência.', 'Fortalecimento dos fibulares (peroneais) para estabilidade lateral.', true, true, NOW()),
('apoio-unipodal', 'Apoio Unipodal', 'Propriocepção', 'iniciante', ARRAY[]::text[], 3, 30, '/exercises/illustrations/apoio-unipodal.avif', 'Fique em um pé só, mantendo a postura ereta e o quadril alinhado. Tente manter por 30 segundos ou conforme orientado.', 'Treino de equilíbrio estático e propriocepção.', true, true, NOW()),
('bosu-balance', 'Equilíbrio no BOSU', 'Propriocepção', 'intermediario', ARRAY['BOSU']::text[], 3, 30, '/exercises/illustrations/equilibrio-bosu.avif', 'Suba no BOSU (lado macio para cima) e tente manter o equilíbrio, mantendo os joelhos levemente flexionados.', 'Treino de equilíbrio em superfície instável.', true, true, NOW()),
('disco-proprioceptivo', 'Disco Proprioceptivo', 'Propriocepção', 'iniciante', ARRAY['Disco Proprioceptivo']::text[], 3, 30, '/exercises/illustrations/disco-proprioceptivo.avif', 'Fique em pé sobre o disco de equilíbrio e tente manter o centro, evitando que as bordas toquem o chão.', 'Treino de reações de equilíbrio e estabilidade de tornozelo.', true, true, NOW()),
('salto-unipodal', 'Salto Unipodal', 'Pliometria / RTS', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/salto-unipodal-aterrissagem.avif', 'Salte para frente ou para cima com uma perna e amorteça a queda com o mesmo pé, mantendo o joelho alinhado e estável.', 'Treino de potência e controle de aterrissagem unipodal.', true, true, NOW()),
('elevacao-lateral', 'Elevação Lateral', 'Ombro', 'iniciante', ARRAY['Halter']::text[], 3, 12, '/exercises/illustrations/elevacao-lateral-de-ombro-0-90.avif', 'Com halteres nas mãos, levante os braços lateralmente até a altura dos ombros, mantendo uma leve flexão nos cotovelos.', 'Fortalecimento de deltoide médio.', true, true, NOW()),
('elevacao-frontal', 'Elevação Frontal', 'Ombro', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/elevacao-frontal-de-ombro.avif', 'Levante os braços à frente do corpo até a altura dos ombros, mantendo o tronco estável.', 'Fortalecimento de deltoide anterior.', true, true, NOW()),
('rot-ext-ombro', 'Rotação Externa de Ombro', 'Ombro', 'iniciante', ARRAY['Theraband', 'Halter']::text[], 3, 12, '/exercises/illustrations/rotacao-externa-ombro.avif', 'Com o cotovelo junto ao corpo, puxe a faixa elástica para fora, rodando o ombro, e retorne devagar.', 'Fortalecimento do manguito rotador (infraespinhal e redondo menor).', true, true, NOW()),
('rot-int-ombro', 'Rotação Interna de Ombro', 'Ombro', 'iniciante', ARRAY['Faixa Elástica']::text[], 3, 12, '/exercises/illustrations/rotacao-interna-ombro.avif', 'Com o cotovelo junto ao corpo, puxe a faixa elástica em direção ao abdômen, rodando o ombro para dentro.', 'Fortalecimento do subescapular.', true, true, NOW()),
('full-can', 'Full Can', 'Ombro', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/full-can.avif', 'Com os polegares virados para cima, levante os braços em um ângulo de 30 graus à frente do corpo (plano da escápula) até a altura dos ombros.', 'Exercício seguro para fortalecimento de supraespinhal.', true, true, NOW()),
('crucifixo-reverso', 'Crucifixo Reverso', 'Ombro', 'iniciante', ARRAY['Faixa Elástica']::text[], 3, 12, '/exercises/illustrations/crucifixo-reverso.avif', 'Com o tronco inclinado ou em pé com faixa elástica, abra os braços para trás aproximando as escápulas.', 'Fortalecimento de deltoide posterior e romboides.', true, true, NOW()),
('pendular-codman', 'Exercício Pendular de Codman', 'Ombro', 'iniciante', ARRAY[]::text[], 3, 15, '/exercises/illustrations/codman-pendular.avif', 'Incline o corpo para frente apoiando em uma mesa e deixe o braço afetado pendurado. Faça círculos suaves e movimentos de balanço.', 'Mobilização passiva de ombro para fase inicial de reabilitação.', true, true, NOW()),
('wall-slides', 'Deslizamento na Parede', 'Ombro / Escápula', 'iniciante', ARRAY['Parede']::text[], 3, 12, '/exercises/illustrations/wall-angels.avif', 'Encoste as costas e os braços na parede em posição de ''U'' e deslize-os para cima e para baixo sem perder o contato com a parede.', 'Treino de controle escapular e mobilidade torácica.', true, true, NOW()),
('serratus-punch', 'Serrátil Punch', 'Escápula', 'iniciante', ARRAY['Parede']::text[], 3, 12, '/exercises/illustrations/serratus-punch.png', 'Deitado de costas ou contra a parede, empurre as mãos para frente como se quisesse afastar as escápulas da coluna, sem dobrar os cotovelos.', 'Ativação do serrátil anterior para estabilidade escapular.', true, true, NOW()),
('retracão-escapular', 'Retração Escapular', 'Escápula', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/retracao-escapular.avif', 'Puxe os ombros para trás, tentando ''esmagar'' uma uva imaginária entre as escápulas, mantendo os ombros baixos.', 'Exercício para fortalecimento dos retratores da escápula (romboides e trapézio médio).', true, true, NOW()),
('rosca-biceps', 'Rosca Bíceps', 'Cotovelo / Braço', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/bicep-curl-alternado.avif', 'Com os braços estendidos ao lado do corpo, dobre os cotovelos trazendo o peso em direção aos ombros e retorne devagar.', 'Fortalecimento isolado do bíceps braquial.', true, true, NOW()),
('extensao-triceps', 'Extensão de Tríceps', 'Cotovelo / Braço', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/extensao-de-cotovelo-com-garrafa.png', 'Estenda o braço sobre a cabeça e dobre o cotovelo levando a mão atrás da nuca, depois estenda-o completamente para cima.', 'Fortalecimento isolado do tríceps braquial.', true, true, NOW()),
('flexao-punho', 'Flexão de Punho', 'Antebraço', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/flexao-punho.avif', 'Com o antebraço apoiado e a palma da mão para cima, dobre o punho trazendo o peso para cima e retorne devagar.', 'Fortalecimento dos flexores do punho.', true, true, NOW()),
('extensao-punho', 'Extensão de Punho', 'Antebraço', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/extensao-punho.avif', 'Com o antebraço apoiado e a palma da mão para baixo, levante as costas da mão em direção ao teto e retorne devagar.', 'Fortalecimento dos extensores do punho.', true, true, NOW()),
('supinacao-pronacao', 'Supinação e Pronação', 'Antebraço', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/supinacao-pronacao.avif', 'Segurando um peso (ou martelo), rode o antebraço para fora (palma para cima) e para dentro (palma para baixo) com controle.', 'Exercício para mobilidade e força rotacional do antebraço.', true, true, NOW()),
('flexbar-tyler', 'Tyler Twist', 'Cotovelo', 'intermediario', ARRAY['Barra']::text[], 3, 12, '/exercises/illustrations/tyler-twist.avif', 'Segurando uma barra flexível (FlexBar), realize a torção com a mão não afetada e controle o desenrolar com a mão afetada.', 'Exercício excêntrico para epicondilite lateral.', true, true, NOW()),
('grip-strengthening', 'Fortalecimento de Preensão', 'Mão', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/fortalecimento-preensao-bolinha.avif', 'Aperte uma bolinha de borracha ou um hand-grip com força máxima e solte lentamente.', 'Fortalecimento da força de preensão manual.', true, true, NOW()),
('finger-extension', 'Extensão de Dedos', 'Mão', 'iniciante', ARRAY['Faixa Elástica']::text[], 3, 15, '/exercises/illustrations/extensao-dedos-elastico.avif', 'Coloque um elástico ao redor dos dedos e tente abri-los contra a resistência do elástico.', 'Fortalecimento dos extensores de dedos e intrínsecos da mão.', true, true, NOW()),
('prancha-ventral', 'Prancha Ventral', 'Core', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/prancha-frontal.avif', 'Apoie os antebraços e as pontas dos pés no chão, mantenha o corpo alinhado como uma tábua, contraindo abdômen e glúteos.', 'Estabilização isométrica do core.', true, true, NOW()),
('prancha-lateral', 'Prancha Lateral', 'Core', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/prancha-lateral.avif', 'Deitado de lado, apoie o antebraço e levante o quadril do chão, mantendo uma linha reta dos pés à cabeça.', 'Estabilização do core com foco nos oblíquos e glúteo médio.', true, true, NOW()),
('dead-bug', 'Dead Bug', 'Core', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/dead-bug.avif', 'Deitado de costas, levante braços e pernas. Desça o braço e a perna opostos lentamente sem deixar a coluna lombar sair do chão.', 'Dissociação de membros com estabilização lombar.', true, true, NOW()),
('bird-dog', 'Bird Dog', 'Core', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/bird-dog.avif', 'Em quatro apoios, estenda o braço e a perna opostos simultaneamente, mantendo a coluna neutra e o quadril nivelado.', 'Estabilização do core em quatro apoios com foco em paravertebrais e glúteos.', true, true, NOW()),
('pallof-press', 'Pallof Press', 'Core', 'intermediario', ARRAY['Faixa Elástica']::text[], 3, 12, '/exercises/illustrations/pallof-press.avif', 'Em pé de lado para a polia ou faixa, segure o puxador com as duas mãos e estenda os braços à frente, resistindo à força que tenta girar seu tronco.', 'Exercício de anti-rotação para estabilidade lombo-pélvica profunda.', true, true, NOW()),
('stir-the-pot', 'Stir the Pot', 'Core', 'avancado', ARRAY['Bola Suíça']::text[], 4, 8, '/exercises/illustrations/stir-the-pot.avif', 'Em posição de prancha com os antebraços sobre uma bola suíça, realize pequenos círculos com os braços mantendo o tronco imóvel.', 'Estabilização dinâmica avançada do core em base instável.', true, true, NOW()),
('abdominal-crunch', 'Abdominal', 'Core', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/abdominal-crupeado.avif', 'Deitado de costas, levante levemente os ombros do chão contraindo o abdômen, mantendo a lombar apoiada.', 'Fortalecimento do reto abdominal com foco em flexão torácica.', true, true, NOW()),
('abdominal-reverso', 'Abdominal Reverso', 'Core', 'iniciante', ARRAY[]::text[], 3, 12, '/exercises/illustrations/abdominal-reverso.avif', 'Deitado de costas, traga os joelhos em direção ao peito, levantando levemente o quadril do chão, e retorne de forma controlada.', 'Foco na porção infra-abdominal e controle pélvico.', true, true, NOW()),
('bicycle-crunch', 'Abdominal Bicicleta', 'Core', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/abdominal-bicicleta.avif', 'Deitado de costas, realize movimentos de pedalada com as pernas enquanto aproxima o cotovelo oposto do joelho que sobe.', 'Fortalecimento de oblíquos e reto abdominal em padrão dinâmico.', true, true, NOW()),
('russian-twist', 'Giro Russo', 'Core', 'intermediario', ARRAY[]::text[], 3, 12, '/exercises/illustrations/rotacao-tronco-sentado.avif', 'Sentado com os joelhos dobrados e pés levemente fora do chão, gire o tronco de um lado para o outro tocando as mãos no solo.', 'Fortalecimento de oblíquos e controle rotacional.', true, true, NOW()),
