('rotacao-tronco', 'Rotação de Tronco', 'Coluna Torácica', 'iniciante', ARRAY[]::text[], 3, 15, '/exercises/illustrations/mobilidade-coluna-sentado.avif', 'Deitado de lado com os joelhos dobrados, abra o braço de cima para o lado oposto, tentando encostar o ombro no chão.', 'Melhora da mobilidade rotacional da coluna torácica.', true, true, NOW()),
